 ('cd35895e-1ae3-59fb-a11f-249aba32a0b6','dd446609-3a20-5a06-a177-c9c1a2b47298',2,$p$Passé composé → plus-que-parfait; futur → conditionnel$p$,$p$Passé composé → plus-que-parfait; futur → conditionnel$p$,'lesson',15),
 ('dd1a05b2-8550-584e-b59f-e54c72a12430','dd446609-3a20-5a06-a177-c9c1a2b47298',3,$p$La interrogación indirecta (si / ce que / ce qui)$p$,$p$La interrogación indirecta (si / ce que / ce qui)$p$,'lesson',15),
 ('3a71f19b-3d3c-5ade-bec9-141f9f42d05b','dd446609-3a20-5a06-a177-c9c1a2b47298',4,$p$Imperativo → de + infinitivo y marcadores temporales$p$,$p$Imperativo → de + infinitivo y marcadores temporales$p$,'lesson',15),
 ('7eb1ae3a-8f0b-508e-89c5-c9830de86460','dd446609-3a20-5a06-a177-c9c1a2b47298',5,$p$🏁 Checkpoint Unité 21$p$,$p$Reporta en pasado con la concordancia de tiempos (présent→imparfait, passé composé→plus-que-parfait, futur→conditionnel), maneja la interrogación indirecta (si / ce que / ce qui / où-quand-pourquoi), transforma el imperativo en «de + infinitivo» y adapta los marcadores temporales (hier→la veille, demain→le lendemain).$p$,'checkpoint',40)
