('58467235-1e93-58d8-a95b-4ac08821e9a0'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','multiple_choice',$p$«Aunque esté cansado, sigue trabajando.» «Bien que» exige subjuntivo. ¿Cuál es correcta?$p$,$j${"options": ["Bien qu'il soit fatigué, il continue à travailler.", "Bien qu'il est fatigué, il continue à travailler.", "Bien qu'il sera fatigué, il continue à travailler."]}$j$::jsonb,$j${"value": "Bien qu'il soit fatigué, il continue à travailler."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$bien_que_subjonctif_choice$p$, $p$reading$p$]),
('7ac163ca-f9b0-5eee-8c5c-efe981da2e52'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','translation',$p$Traduce (usa «pour que» + subjuntivo): «Te lo explico para que entiendas.»$p$,$j${"source": "Te lo explico para que entiendas."}$j$::jsonb,$j${"value": "Je te l'explique pour que tu comprennes.", "accepted": ["Je te l'explique pour que tu comprennes", "Je te l'explique pour que tu comprennes.", "Je te l'explique afin que tu comprennes.", "Je te l'explique afin que tu comprennes"]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$pour_que_subjonctif_translation$p$, $p$writing$p$]),
('cb9ac846-4029-5f4e-b7c1-da07c96cfadb'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','match',$p$Une cada conjunción (todas rigen subjuntivo) con su significado.$p$,$j${"pairs": [{"en": "bien que", "es": "aunque"}, {"en": "pour que", "es": "para que"}, {"en": "quoique", "es": "aunque, por más que"}, {"en": "afin que", "es": "a fin de que"}]}$j$::jsonb,$j${"pairs": [["bien que", "aunque"], ["pour que", "para que"], ["quoique", "aunque, por más que"], ["afin que", "a fin de que"]]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$conjonctions_subjonctif_forms$p$, $p$reading$p$]),
('b86424da-edc3-5ff6-89d5-553adf4ec023'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Je parle lentement pour que tout le monde comprenne.", "Je parle lentement parce que tout le monde comprend.", "Je parle doucement afin que personne ne comprenne."], "say": "Je parle lentement pour que tout le monde comprenne.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b86424da-edc3-5ff6-89d5-553adf4ec023.mp3"}$j$::jsonb,$j${"value": "Je parle lentement pour que tout le monde comprenne."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$pour_que_listening$p$, $p$listening$p$]),
('2ff9ae6f-c896-57bc-9bad-747010529f73'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Bien que le trajet soit long, nous préférons prendre le train.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/2ff9ae6f-c896-57bc-9bad-747010529f73.mp3"}$j$::jsonb,$j${"expected": "Bien que le trajet soit long, nous préférons prendre le train."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$bien_que_speaking$p$, $p$speaking$p$]),
('af7ddb0a-0525-5073-a1f4-4dcdeba4bead'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','multiple_choice',$p$«Vendré con tal de que no llueva.» «à condition que / pourvu que» exigen subjuntivo. ¿Cuál es correcta?$p$,$j${"options": ["Je viendrai à condition qu'il ne pleuve pas.", "Je viendrai à condition qu'il ne pleut pas.", "Je viendrai à condition qu'il ne pleuvra pas."]}$j$::jsonb,$j${"value": "Je viendrai à condition qu'il ne pleuve pas."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$a_condition_que_choice$p$, $p$reading$p$]),
('f786b4f4-aba2-58c8-a267-5ccc2eeb06eb'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','cloze',$p$Completa con el subjuntivo de «finir» (3ª pers.) tras «avant que»: esta conjunción SIEMPRE exige subjuntivo. Escribe «finisse».$p$,$j${"text": "Rentrons avant que la réunion ne ___ trop tard."}$j$::jsonb,$j${"value": "finisse", "accepted": ["finisse"]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$avant_que_subjonctif_cloze$p$, $p$writing$p$]),
('e6071571-66b3-5529-ba12-f5a83478ef43'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','translation',$p$Traduce (usa «à moins que» + ne explétif + subjuntivo): «No saldremos a menos que haga buen tiempo.»$p$,$j${"source": "No saldremos a menos que haga buen tiempo."}$j$::jsonb,$j${"value": "Nous ne sortirons pas à moins qu'il ne fasse beau.", "accepted": ["Nous ne sortirons pas à moins qu'il ne fasse beau", "Nous ne sortirons pas à moins qu'il ne fasse beau.", "On ne sortira pas à moins qu'il ne fasse beau.", "Nous ne sortirons pas à moins qu'il fasse beau."]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$a_moins_que_translation$p$, $p$writing$p$]),
('e4286d79-cb48-54e3-9965-aa857f0ab0c9'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Je te prête ma voiture pourvu que tu conduises prudemment.", "Je te loue ma voiture puisque tu conduis prudemment.", "Je te vends ma voiture bien que tu conduises rapidement."], "say": "Je te prête ma voiture pourvu que tu conduises prudemment.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/e4286d79-cb48-54e3-9965-aa857f0ab0c9.mp3"}$j$::jsonb,$j${"value": "Je te prête ma voiture pourvu que tu conduises prudemment."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$a_condition_que_listening$p$, $p$listening$p$]),
('bb860d19-7071-5d1a-b731-3a904f7e03cf'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Dépêchons-nous de finir avant que les invités n'arrivent.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/bb860d19-7071-5d1a-b731-3a904f7e03cf.mp3"}$j$::jsonb,$j${"expected": "Dépêchons-nous de finir avant que les invités n'arrivent."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$avant_que_speaking$p$, $p$speaking$p$]),
('16acf7af-f80a-5a3f-9258-cd69066df338'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','multiple_choice',$p$«Yo trabajo mientras que él descansa.» «alors que» (oposición) exige INDICATIVO, no subjuntivo. ¿Cuál es correcta?$p$,$j${"options": ["Je travaille alors qu'il se repose.", "Je travaille alors qu'il se repose pas.", "Je travaille alors qu'il se reposât."]}$j$::jsonb,$j${"value": "Je travaille alors qu'il se repose."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$alors_que_indicatif_choice$p$, $p$reading$p$]),
('3368a68c-770a-5e21-83f7-aacc77103777'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','match',$p$Une cada conjunción con su valor (todas van con indicativo).$p$,$j${"pairs": [{"en": "tandis que", "es": "mientras que (oposición/simultaneidad)"}, {"en": "parce que", "es": "porque (causa)"}, {"en": "puisque", "es": "puesto que (causa conocida)"}, {"en": "pendant que", "es": "mientras (simultaneidad)"}]}$j$::jsonb,$j${"pairs": [["tandis que", "mientras que (oposición/simultaneidad)"], ["parce que", "porque (causa)"], ["puisque", "puesto que (causa conocida)"], ["pendant que", "mientras (simultaneidad)"]]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$tandis_que_alors_que_forms$p$, $p$reading$p$]),
('d0d9959c-140e-5021-b3b0-b21b109129b5'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','cloze',$p$Completa con el indicativo presente de «préférer» (3ª pers.): tras «tandis que» NO va subjuntivo. «J'aime le thé, tandis qu'elle ___ le café.» Escribe «préfère».$p$,$j${"text": "J'aime le thé, tandis qu'elle ___ le café."}$j$::jsonb,$j${"value": "préfère", "accepted": ["préfère", "prefere"]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$tandis_que_indicatif_cloze$p$, $p$writing$p$]),
('5ba2e989-41fb-5ee0-94e8-c7f44fb6c2d8'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Il dépense tout son argent alors que son frère économise beaucoup.", "Il gagne tout son argent puisque son frère travaille beaucoup.", "Il garde tout son argent tandis que son frère voyage souvent."], "say": "Il dépense tout son argent alors que son frère économise beaucoup.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/5ba2e989-41fb-5ee0-94e8-c7f44fb6c2d8.mp3"}$j$::jsonb,$j${"value": "Il dépense tout son argent alors que son frère économise beaucoup."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$alors_que_listening$p$, $p$listening$p$]),
