('8f4d5ff0-0aed-50b7-b12f-dc57678160a3'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','reading','multiple_choice',$p$«El proyecto es ambicioso; sin embargo, carece de presupuesto.» Elige el conector de OPOSICIÓN adecuado.$p$,$j${"options": ["Le projet est ambitieux ; cependant, il manque de budget.", "Le projet est ambitieux ; par conséquent, il manque de budget.", "Le projet est ambitieux ; en effet, il manque de budget."]}$j$::jsonb,$j${"value": "Le projet est ambitieux ; cependant, il manque de budget."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$cependant_opposition_choice$p$, $p$reading$p$]),
('d5d2fe2a-bceb-568d-a561-eabb1cf90e14'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','cloze',$p$Completa con el conector de CONSECUENCIA (dos palabras, «par c...»): «La route est fermée ; ___ ___, nous devrons faire un détour.» Escribe «par conséquent».$p$,$j${"text": "La route est fermée ; ___, nous devrons faire un détour."}$j$::jsonb,$j${"value": "par conséquent", "accepted": ["par conséquent", "par consequent"]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$par_consequent_cloze$p$, $p$writing$p$]),
('55c57cd7-b42d-5ad0-8070-923aa7ad83e2'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','writing','translation',$p$Traduce (usa «en revanche» para el contraste): «El hotel es caro; en cambio, el servicio es excelente.»$p$,$j${"source": "El hotel es caro; en cambio, el servicio es excelente."}$j$::jsonb,$j${"value": "L'hôtel est cher ; en revanche, le service est excellent.", "accepted": ["L'hôtel est cher ; en revanche, le service est excellent", "L'hôtel est cher ; en revanche, le service est excellent.", "L'hôtel est cher, en revanche le service est excellent.", "L'hotel est cher ; en revanche, le service est excellent."]}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$en_revanche_translation$p$, $p$writing$p$]),
('427f0f15-240b-5e6d-859f-3f473faa3b1b'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Les prix ont augmenté ; néanmoins, la demande reste très forte.", "Les prix ont baissé ; par ailleurs, la demande devient très faible.", "Les prix ont grimpé ; en outre, la demande semble assez stable."], "say": "Les prix ont augmenté ; néanmoins, la demande reste très forte.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/427f0f15-240b-5e6d-859f-3f473faa3b1b.mp3"}$j$::jsonb,$j${"value": "Les prix ont augmenté ; néanmoins, la demande reste très forte."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$connecteurs_listening$p$, $p$listening$p$])
