 ('c3b5942f-ea4e-5deb-8076-004688ffcaab','20000000-0000-0000-0000-000000000003','B2',24,$p$Voz pasiva avanzada, formas impersonales y puesta de relieve$p$,'#1A5276','published_with_changes')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('287bd24d-873b-5a15-b05e-8e852929d435','c3b5942f-ea4e-5deb-8076-004688ffcaab',1,$p$La voix passive: formación, concordancia y tiempos$p$,$p$La voix passive: formación, concordancia y tiempos$p$,'lesson',15),
 ('32354f3a-7e82-578b-a629-98763ba07d78','c3b5942f-ea4e-5deb-8076-004688ffcaab',2,$p$Alternativas a la pasiva: on, se faire + inf, forme pronominale$p$,$p$Alternativas a la pasiva: on, se faire + inf, forme pronominale$p$,'lesson',15),
 ('67d64d4e-bd21-5d98-9d9d-642b177932c1','c3b5942f-ea4e-5deb-8076-004688ffcaab',3,$p$Tournures impersonnelles: il est important que, il s'agit de…$p$,$p$Tournures impersonnelles: il est important que, il s'agit de…$p$,'lesson',15),
 ('a692e24b-f40b-5cb9-bb2f-206fcd0c5e5f','c3b5942f-ea4e-5deb-8076-004688ffcaab',4,$p$Mise en relief: c'est… qui / ce que… c'est$p$,$p$Mise en relief: c'est… qui / ce que… c'est$p$,'lesson',15),
 ('aa54fbe0-447a-5b4d-82b3-0f0bc3a80a37','c3b5942f-ea4e-5deb-8076-004688ffcaab',5,$p$🏁 Checkpoint Unité 24$p$,$p$Demuestra que dominas la voix passive (être + participe passé con concordancia y en varios tiempos, complemento de agente par/de), sus alternativas (on, se faire + infinitif, forme pronominale de sens passif), las tournures impersonnelles (il est important que + subj, il paraît que, il s'agit de, il suffit de, il vaut mieux que + subj) y la mise en relief (c'est… qui / c'est… que, ce que… c'est, ce dont… c'est).$p$,'checkpoint',40)
